--- a/packages/ui/src/engine/pixel-characters.ts
+++ b/packages/ui/src/engine/pixel-characters.ts
@@ -715,6 +715,62 @@
 function drawWorkshop(ctx: CanvasRenderingContext2D, x: number, y: number, w: number, h: number, frame: number) {
   const bx = x + w * 0.1, by = y + h * 0.52;
   ctx.fillStyle = '#4a2810'; ctx.fillRect(bx, by, w * 0.75, h * 0.1);
   ctx.fillStyle = '#5c3418'; ctx.fillRect(bx + 2, by + 1, w * 0.75 - 4, h * 0.08);
   ctx.fillStyle = '#3a1e08';
   ctx.fillRect(bx + 2, by + h * 0.1, 4, h * 0.1);
   ctx.fillRect(bx + w * 0.72, by + h * 0.1, 4, h * 0.1);
   ctx.fillStyle = '#7f8c8d';
   ctx.fillRect(bx + 10, by - 2, 3, 8); ctx.fillRect(bx + 20, by - 4, 2, 10);
   ctx.fillStyle = '#5a3a18'; ctx.fillRect(bx + 8, by + 3, 7, 3);
   ctx.fillStyle = '#7f8c8d'; ctx.fillRect(bx + 6, by + 1, 4, 3);
   // Tool rack
   ctx.fillStyle = '#3a2010'; ctx.fillRect(x + w * 0.1, y + h * 0.12, w * 0.25, 4);
   for (let i = 0; i < 4; i++) {
     ctx.fillStyle = '#7f8c8d'; ctx.fillRect(x + w * 0.12 + i * 12, y + h * 0.12 + 4, 2, 10 + i * 2);
   }
+}
+
+function drawSoundIndicator(ctx: CanvasRenderingContext2D, x: number, y: number, type: string, frame: number) {
+  const size = 10;
+  ctx.save();
+  ctx.lineWidth = 1;
+  ctx.lineCap = 'round';
+  switch (type) {
+    case 'forge': {
+      // Orange impact lines radiating outward, 4 frames
+      const colors = ['#ff8c00', '#ffa500', '#ffb733', '#ffcc66'];
+      ctx.strokeStyle = colors[frame % 4];
+      const centerX = x + size / 2;
+      const centerY = y + size / 2;
+      const length = 6 + frame * 2;
+      for (let i = 0; i < 8; i++) {
+        const angle = (Math.PI / 4) * i;
+        const dx = Math.cos(angle) * length;
+        const dy = Math.sin(angle) * length;
+        ctx.beginPath();
+        ctx.moveTo(centerX, centerY);
+        ctx.lineTo(centerX + dx, centerY + dy);
+        ctx.stroke();
+      }
+      break;
+    }
+    case 'scribe': {
+      // Musical note icons floating up, 4 frames
+      ctx.fillStyle = '#4a90e2';
+      const noteX = x + size / 2;
+      const baseY = y + size - frame * 2;
+      // Draw note stem
+      ctx.fillRect(noteX + 2, baseY - 8, 1.5, 8);
+      // Draw note head (circle)
+      ctx.beginPath();
+      ctx.ellipse(noteX, baseY - 4, 3, 4, 0, 0, Math.PI * 2);
+      ctx.fill();
+      // Draw flag
+      ctx.beginPath();
+      ctx.moveTo(noteX + 3.5, baseY - 8);
+      ctx.quadraticCurveTo(noteX + 7, baseY - 10 - frame, noteX + 3, baseY - 12 - frame);
+      ctx.strokeStyle = '#4a90e2';
+      ctx.lineWidth = 1.2;
+      ctx.stroke();
+      break;
+    }
+    case 'healer': {
+      // Concentric magic circles expanding, 4 frames
+      const colors = ['#a0e0ff', '#70c0ff', '#40a0ff', '#1080ff'];
+      ctx.strokeStyle = colors[frame % 4];
+      ctx.lineWidth = 1.5;
+      const centerX = x + size / 2;
+      const centerY = y + size / 2;
+      for (let i = 0; i < 3; i++) {
+        const radius = 3 + frame * 2 + i * 3;
+        ctx.beginPath();
+        ctx.ellipse(centerX, centerY, radius, radius, 0, 0, Math.PI * 2);
+        ctx.stroke();
+      }
+      break;
+    }
+    case 'watchtower': {
+      // Exclamation alert icons, 4 frames (pulsing)
+      const colors = ['#ff0000', '#ff3333', '#ff6666', '#ff9999'];
+      ctx.fillStyle = colors[frame % 4];
+      const centerX = x + size / 2;
+      const centerY = y + size / 2;
+      // Draw exclamation line
+      ctx.fillRect(centerX - 1, centerY - 4, 2, 6);
+      // Draw dot
+      ctx.beginPath();
+      ctx.ellipse(centerX, centerY + 4, 2, 2, 0, 0, Math.PI * 2);
+      ctx.fill();
+      break;
+    }
+  }
+  ctx.restore();
 }
+
+// Add calls to drawSoundIndicator near relevant furniture in drawWorkshop, drawScriptorium, drawSanctum, drawWatchtower, drawForge
+
+function drawScriptorium(ctx: CanvasRenderingContext2D, x: number, y: number, w: number, h: number, frame: number) {
+  // Existing drawing code placeholder (not shown in snippet)
+  // For demonstration, assume similar to others, draw furniture here...
+  // Draw sound indicator near furniture
+  drawSoundIndicator(ctx, x + w * 0.7, y + h * 0.5, 'scribe', frame % 4);
+}
+
+function drawSanctum(ctx: CanvasRenderingContext2D, x: number, y: number, w: number, h: number, frame: number) {
+  // Existing drawing code placeholder (not shown in snippet)
+  // Draw sound indicator near furniture
+  drawSoundIndicator(ctx, x + w * 0.5, y + h * 0.5, 'healer', frame % 4);
+}
+
+function drawWatchtower(ctx: CanvasRenderingContext2D, x: number, y: number, w: number, h: number, frame: number) {
+  // Existing drawing code as before
+  const rx = x + w * 0.03, ry = y + h * 0.08;
+  ctx.fillStyle = '#3a2010'; ctx.fillRect(rx, ry, w * 0.12, h * 0.32);
+  ctx.fillStyle = '#4a2a14'; ctx.fillRect(rx + 2, ry + 2, w * 0.12 - 4, h * 0.32 - 4);
+  for (let i = 0; i < 3; i++) {
+    const sx = rx + 4 + i * 8;
+    ctx.fillStyle = '#9a9aaa'; ctx.fillRect(sx, ry + 4, 2, h * 0.24);
+    ctx.fillStyle = '#5a3a18'; ctx.fillRect(sx - 1, ry + h * 0.22, 4, 4);
+    ctx.fillStyle = P.gold[2]; ctx.fillRect(sx - 2, ry + h * 0.2, 6, 2);
+  }
+  // Shield
+  ctx.fillStyle = '#2a4080';
+  ctx.beginPath();
+  const shx = rx + w * 0.14 + 10;
+  ctx.moveTo(shx, ry + 2); ctx.lineTo(shx + 10, ry + 6); ctx.lineTo(shx + 10, ry + 20);
+  ctx.lineTo(shx + 5, ry + 26); ctx.lineTo(shx, ry + 20); ctx.lineTo(shx - 10, ry + 6);
+  ctx.closePath(); ctx.fill();
+  ctx.fillStyle = P.gold[3]; ctx.fillRect(shx - 2, ry + 10, 6, 2); ctx.fillRect(shx, ry + 6, 2, 14);
+
+  // Training dummy
+  const dx = x + w * 0.78, dy = y + h * 0.35;
+  ctx.fillStyle = '#6a5a40'; ctx.fillRect(dx + 6, dy, 4, 30);
+  ctx.fillStyle = '#8a7a58'; ctx.fillRect(dx, dy + 4, 16, 4); ctx.fillRect(dx + 3, dy - 2, 10, 8);
+  ctx.fillStyle = '#a0906a'; ctx.beginPath(); ctx.arc(dx + 8, dy - 2, 6, 0, Math.PI * 2); ctx.fill();
+
+  ctx.fillStyle = '#4a2810'; ctx.fillRect(x + w * 0.3, y + h * 0.55, w * 0.4, h * 0.1);
+  ctx.fillStyle = '#5c3418'; ctx.fillRect(x + w * 0.31, y + h * 0.56, w * 0.38, h * 0.08);
+  drawTorch(ctx, x + w * 0.5, y + h * 0.06, frame);
+
+  drawSoundIndicator(ctx, x + w * 0.5, y + h * 0.3, 'watchtower', frame % 4);
+}
+
+function drawForge(ctx: CanvasRenderingContext2D, x: number, y: number, w: number, h: number, frame: number) {
+  // Existing drawing code placeholder (not shown in snippet)
+  // Draw sound indicator near forge
+  drawSoundIndicator(ctx, x + w * 0.6, y + h * 0.5, 'forge', frame % 4);
+}
